#nullable enable // autogenerated  

using MVZ2.GameContent.Buffs.Contraptions;
using MVZ2.Vanilla.Audios;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Contraptions  
{  
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.BrainInVat)]  
    public class BrainInVat : ContraptionBehaviour  
    {  
        public BrainInVat(string nsp, string name) : base(nsp, name) { }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            // 放置即进入上帝模式
            entity.Level.SetGodMode(true);
        }

        // 以任何形式被摧毁:先离开上帝模式,再强制游戏失败  
        public override void PostDeath(Entity entity, DeathInfo info)
        {
            base.PostDeath(entity, info);
            entity.Level.SetGodMode(false);
            if (entity.Level.IsCleared)
                return;
            entity.Level.GameOver(GameOverTypes.INSTANT, null, null);
        }

        // 星之碎片/碎片能力：获得10秒无敌（石护罩大招buff）  
        protected override void OnEvoke(Entity entity)  
        {  
            base.OnEvoke(entity);  
            var buff = entity.GetFirstBuff<IronCurtainBuff>() ?? entity.AddBuff<IronCurtainBuff>();  
            buff.SetProperty(IronCurtainBuff.PROP_TIMEOUT, IronCurtainBuff.MAX_TIMEOUT);  
            entity.PlaySound(VanillaSoundID.ironCurtain);  
        }
        public override bool CanEvoke(Entity entity)
        {
            // 已有铁幕(无敌)buff时不能再开大，防止无限刷新叠加  
            if (entity.HasBuff<IronCurtainBuff>())
                return false;
            return base.CanEvoke(entity);
        }
    }  
}
